import React, { useState } from 'react';
import BrandImage from '../../assets/graphics/brand1.png'
import HeaderNavbar from '../navbar/Navbar'
import './Header.css'

const Header: React.FunctionComponent = () => {
    const navbarItems = [
        {
            name: "Work",
            url: "/work"

        },
        {
            name: "About Me",
            url: "/aboutMe"

        },
        {
            name: "Work",
            url: "/work"

        },
    ]
    return (
        <div>
            <HeaderNavbar brandImage={BrandImage} color={"fade"} brand={"Boon Chi"} item={navbarItems}></HeaderNavbar>
        </div>
    )

};

export default Header;
